const expiry = new Date(items[0].json['Expiry Date']);
const today = new Date();
const days = Math.ceil((expiry - today) / (1000*60*60*24));
items[0].json.daysUntilExpiry = days;
items[0].json.urgency = days <= 7 ? 'URGENT' : days <= 14 ? 'HIGH' : 'REMINDER';
return items;

